import React, { useState } from 'react';
import Select, { components } from 'react-select';
import { BuildingCheck, Person,ChevronDown } from 'react-bootstrap-icons';

const SelectOption = () => {
  const data = [
    {
      value: 1,
      text: 'Floyd Miles',
      icon: <BuildingCheck size={20} color="#667085" className="icon" />,
    },
    {
      value: 2,
      text: 'Ronald Richards',
      icon: <Person size={20} color="#667085" className="icon" />,
    },
    {
      value: 3,
      text: 'Johnson & Johnson',
      icon: <BuildingCheck size={20} color="#667085" className="icon" />,
    },
    {
      value: 4,
      text: 'Jacob Jones',
      icon: <Person size={20} color="#667085" className="icon" />,
    },
  ];

  const defaultOption = data[0];

  const [selectedOption, setSelectedOption] = useState(defaultOption);

  const handleChange = (e) => {
    setSelectedOption(e);
  };

  const DropdownIndicator = (props) => {
    return (
      <components.DropdownIndicator {...props}>
        {/* Change the icon for the dropdown indicator here */}
        <ChevronDown size={20} color="#667085" className="icon" />
     
      </components.DropdownIndicator>
    );
  };

  return (
    <>
      <Select
        placeholder="Select Option"
        value={selectedOption}
        options={data}
        onChange={handleChange}
        components={{ DropdownIndicator }}
        getOptionLabel={(e) => (
          <div style={{ display: 'flex', alignItems: 'center' }}>
            {e.icon}
            <span style={{ marginLeft: 5 }}>{e.text}</span>
          </div>
        )}
      />

      {/* {selectedOption && (
        <div style={{ marginTop: 20, lineHeight: '25px' }}>
          <b>Selected Option:</b> {selectedOption.value}
        </div>
      )} */}
    </>
  );
};

export default SelectOption;
