import React, { useEffect, useState } from "react";
import { NavLink } from "react-router-dom";
import Container from "react-bootstrap/Container";
import Row from "react-bootstrap/Row";
import Col from "react-bootstrap/Col";
import Button from 'react-bootstrap/Button';
import { XCircle,Download,PlusLg } from "react-bootstrap-icons";
import MultiDropdoen from "./MultiDropdoen";
import MultipleWonFilter from "./MultipleWonFilter";

const TableTopBar = ({ salesData, selectedRowCount,selectClass,selectedRow }) => {
  const [totalAmount, setTotalAmount] = useState(0);

  const formattedAmount = totalAmount.toLocaleString("en-US", {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  });

  const styleT1 = { color: "#079455" };
  const styleT2 = {
    borderRadius: "16px",
    border: "1px solid #E9D7FE",
    background: "#F9F5FF",
    color: "#9E77ED",
    fontSize: "12px",
    fontWeight: 400,
    lineHeight: "22px",
    letterSpacing: "0.12px",
    padding: "1px 8px",
    margin: "0 8px",
  };
  const styleT3 = {
    color: "#475467",
    fontSize: "18px",
    fontStyle: "normal",
    fontWeight: 600,
    lineHeight: "24px",
    letterSpacing: "-0.18px",
    margin: "0",
    display: "flex",
    alignItems: "center",
    justifyContent: "flex-end",
  };
  const styleT4 = {
    color: "#9E77ED",
    fontSize: "16px",
    fontStyle: "normal",
    fontWeight: 700,
    lineHeight: "20px",
    letterSpacing: "-0.18px",
    margin: "0",
    display: "flex",
    alignItems: "center",
    justifyContent: "flex-end",
  };

  useEffect(() => {
    if (salesData) {
      const calculatedTotalAmount = salesData.reduce(
        (total, sale) => total + sale.amount,
        0
      );
      setTotalAmount(calculatedTotalAmount);
    }
  }, [salesData]);

  return (
    <div className={`${selectClass} flexbetween paddingLR tableTopBar`}>
     {selectedRow.length === 0 ? (

<Container fluid>
<Row style={{ display: "flex", alignItems: "center" }}>
  <Col style={{ textAlign: "left", display: "flex", alignItems: "center" }}>
      <MultiDropdoen />
   
  </Col>
  <Col>
    <div className="centerTabSales">
      <ul>
        <li>
          <NavLink to="/sales">Sales</NavLink>
        </li>
        <li>
          <NavLink to="/new" className="tabActive">
            New
          </NavLink>
        </li>
      </ul>
    </div>
  </Col>
  <Col style={{ textAlign: "right" }}>
    {salesData && salesData.length > 0 ? (
      <p className="flexEndStyle" style={styleT3}>
        Total <span style={styleT2}>{salesData.length} Sales</span>{" "}
        <strong style={styleT1}>${formattedAmount}</strong>
      </p>
    ) : (
      <p className="flexEndStyle" style={styleT3}>
        Total <span style={styleT2}>0 Sales</span> <strong style={styleT1}>$0.00</strong>
      </p>
    )}
  </Col>
</Row>
</Container>
      ) : (
        <Container fluid>
        <Row style={{ display: "flex", alignItems: "center" }}>
          <Col style={{ textAlign: "left", display: "flex", alignItems: "center" }}>
            <span  style={styleT4}>Selected:{selectedRowCount}</span>
            <ul className="filterBtn">
              <li>
                <Button  variant="lostFilter">Lost
              <XCircle color="#D92D20" size={20} />
               </Button>
            </li>
              <li>
             <MultipleWonFilter />
            </li>
              <li>
                <Button variant="downloadBtn">
                <Download color="#344054" size={20} />
               </Button>
            </li>
            </ul>
          </Col>
          <Col>
            <div className="centerTabSales">
              <ul>
                <li>
                  <NavLink to="/sales">Sales</NavLink>
                </li>
                <li>
                  <NavLink to="/new" className="tabActive">
                    New <PlusLg color="#fff" size={20} />
                  </NavLink>
                </li>
              </ul>
            </div>
          </Col>
          <Col style={{ textAlign: "right" }}>
            {salesData && salesData.length > 0 ? (
              <p className="flexEndStyle" style={styleT3}>
                Total <span style={styleT2}>{salesData.length} Sales</span>{" "}
                <strong style={styleT1}>${formattedAmount}</strong>
              </p>
            ) : (
              <p className="flexEndStyle" style={styleT3}>
                Total <span style={styleT2}>0 Sales</span> <strong style={styleT1}>$0.00</strong>
              </p>
            )}
          </Col>
        </Row>
      </Container>
        )}



     
    </div>
  );
};

export default TableTopBar;
