import React from 'react';
import { Envelope, Telephone, Calendar } from "react-bootstrap-icons";
import { Button, ButtonToolbar, OverlayTrigger, Popover } from 'react-bootstrap';
import ContactAdd from "./ContactAdd";
 // Format Date
 const formatDate = (timestamp) => {
  const date = new Date(timestamp * 1000);
  const day = date.getDate();
  const monthAbbreviation = new Intl.DateTimeFormat("en-US", {
    month: "short",
  }).format(date);
  const year = date.getFullYear();
  return `${day}-${monthAbbreviation}-${year}`;
};
const ContactSales = (props) => {
  return (
    <>
     <div className="innerTableStyle">
        
        <ul>
      {props.type.map((item, index) => (
         <li key={index}>
        <ButtonToolbar key={index}>
          <OverlayTrigger
            trigger="click"
            rootClose
            placement="bottom"
            overlay={
              <Popover id={`popover-trigger-click-root-close-${index}`} title="">
                 <div className="contactInfo">
                      <div className="iconStyle">
                        {item.type === 'Phone' && (
                          <Telephone color="#667085" size={16} />
                        )}
                        {item.type === 'Email' && (
                          <Envelope color="#667085" size={16} />
                        )}
                        {item.type === 'Meeting' && (
                          <Calendar color="#667085" size={16} />
                        )}
                      </div>
                      <p className="contactdate">
                        {formatDate(item.date)}
                      </p>
                      <p>{item.note}</p>
                    </div>
              </Popover>
            }
          >
            <Button variant='saleContacte'>
              <>
                {item.type === 'Phone' && (
                  <Telephone color="#667085" size={16} />
                )}
                {item.type === 'Email' && (
                  <Envelope color="#667085" size={16} />
                )}
                {item.type === 'Meeting' && (
                  <Calendar color="#667085" size={16} />
                )}
                <div>{formatDate(item.date)}</div>
              </>
            </Button>
          </OverlayTrigger>
        </ButtonToolbar>
        </li>
      ))}
         {Array.from({ length: Math.max(3 - props.type.length, 0) }).map(
          (_, index) => (
            <li key={props.type.length + index}>
               <span className="contactButList">
                 <div className="contactButListIn1">
                 <div className="contactButListIn2">
                 <ContactAdd />
                 </div>
                 </div>
                </span>
            </li>
          )
        )}
      </ul>
    </div>
    </>
    
  );
};

export default ContactSales;
